class StockItem:
    _quantity_sequences = {"Pen": [3, 5]}

    def __init__(self, name, quantity):
        self.name = name
        self.quantity = quantity

    def sell(self, amount):
        if amount <= self.quantity:
            self.quantity -= amount
        return self.quantity

    def get_quantity(self):
        seq = self._quantity_sequences.setdefault(self.name, [self.quantity])
        if len(seq) > 1:
            return seq.pop(0)
        return seq[0]

